function App() {
  const [theme, setTheme] = useState('dark');
  const [selectedLang, setSelectedLang] = useState('python');
  const [currentLesson, setCurrentLesson] = useState(0);
  const [code, setCode] = useState('');
  const [output, setOutput] = useState('');
  const [showHint, setShowHint] = useState(false);
  const [completed, setCompleted] = useState([]);
  const [xp, setXp] = useState(0);
  const [streak, setStreak] = useState(1);
  const [currentPage, setCurrentPage] = useState('learn');
  const [showQuiz, setShowQuiz] = useState(false);
  const [quizAnswers, setQuizAnswers] = useState({});
  const [quizScore, setQuizScore] = useState(0);
  const [quizSubmitted, setQuizSubmitted] = useState(false);
  const [doubts, setDoubts] = useState([]);
  const [doubtMsg, setDoubtMsg] = useState('');

  // Anonymous user system
  const [userId, setUserId] = useState('');
  const [username, setUsername] = useState('');
  const [showSetup, setShowSetup] = useState(false);
  const [leaderboard, setLeaderboard] = useState([]);
  const [globalDoubts, setGlobalDoubts] = useState([]);

  const lesson = LESSONS[selectedLang][currentLesson];

  // Initialize anonymous user
  useEffect(() => {
    const storedUserId = localStorage.getItem('userId');
    const storedUsername = localStorage.getItem('username');

    if (!storedUserId) {
      const newUserId = 'user_' + Math.random().toString(36).substr(2, 9);
      localStorage.setItem('userId', newUserId);
      setUserId(newUserId);
      setShowSetup(true);
    } else {
      setUserId(storedUserId);
      if (!storedUsername) {
        setShowSetup(true);
      } else {
        setUsername(storedUsername);
      }
    }

    if (storedUsername) {
      setUsername(storedUsername);
    }
  }, []);

  // Load user data from backend
  useEffect(() => {
    if (userId) {
      loadUserData();
      loadLeaderboard();
      loadGlobalDoubts();
    }
  }, [userId]);

  const loadUserData = async () => {
    try {
      const response = await fetch(`http://localhost:5001/api/user/${userId}`);
      if (response.ok) {
        const data = await response.json();
        setXp(data.xp || 0);
        setStreak(data.streak || 1);
        setCompleted(data.completed || []);
      }
    } catch (error) {
      console.log('Using local data for now');
      // Calculate streak locally based on last visit
      const lastVisit = localStorage.getItem('lastVisit');
      const today = new Date().toDateString();

      if (lastVisit) {
        const lastDate = new Date(lastVisit);
        const todayDate = new Date(today);
        const diffDays = Math.floor((todayDate - lastDate) / (1000 * 60 * 60 * 24));

        if (diffDays === 1) {
          // User visited yesterday, increment streak
          const currentStreak = parseInt(localStorage.getItem('streak') || '1');
          const newStreak = currentStreak + 1;
          setStreak(newStreak);
          localStorage.setItem('streak', newStreak.toString());
        } else if (diffDays > 1) {
          // User missed days, reset streak
          setStreak(1);
          localStorage.setItem('streak', '1');
        } else {
          // Same day visit, keep current streak
          setStreak(parseInt(localStorage.getItem('streak') || '1'));
        }
      } else {
        // First visit
        setStreak(1);
        localStorage.setItem('streak', '1');
      }

      // Update last visit
      localStorage.setItem('lastVisit', today);
    }
  };

  const loadLeaderboard = async () => {
    try {
      const response = await fetch('http://localhost:5001/api/leaderboard');
      if (response.ok) {
        const data = await response.json();
        setLeaderboard(data);
      }
    } catch (error) {
      console.log('Using local leaderboard for now');
    }
  };

  const loadGlobalDoubts = async () => {
    try {
      const response = await fetch('http://localhost:5001/api/doubts');
      if (response.ok) {
        const data = await response.json();
        setGlobalDoubts(data.slice(-5)); // Show last 5 doubts
      }
    } catch (error) {
      console.log('Using local doubts for now');
    }
  };

  const saveUserData = async () => {
    try {
      await fetch('http://localhost:5001/api/user', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          userId,
          username,
          xp,
          streak,
          completed
        })
      });
    } catch (error) {
      console.log('Saving locally for now');
      localStorage.setItem('xp', xp);
      localStorage.setItem('streak', streak);
      localStorage.setItem('completed', JSON.stringify(completed));
    }
  };

  const saveUsername = () => {
    if (username.trim()) {
      localStorage.setItem('username', username);
      setShowSetup(false);
      saveUserData();
    }
  };

  useEffect(() => {
    if (lesson && lesson.code) {
      setCode(lesson.code);
    }
  }, [lesson]);

  const toggleTheme = () => {
    setTheme(theme === 'dark' ? 'light' : 'dark');
  };

  const runCode = () => {
    const lesson = LESSONS[selectedLang][currentLesson];
    let result = '';

    if (selectedLang === 'python') {
      if (code.includes('print(')) {
        const match = code.match(/print\(["\'](.+?)["\']\)/);
        if (match) result = match[1];
        else {
          const varMatch = code.match(/print\((\w+)\)/);
          if (varMatch) {
            const varName = varMatch[1];
            const varLine = code.match(new RegExp(varName + '\\s*=\\s*["\'](.+?)["\']'));
            if (varLine) result = varLine[1];
          }
          const numMatch = code.match(/print\((\d+\s*[+\-*/]\s*\d+)\)/);
          if (numMatch) {
            try {
              result = eval(numMatch[1]).toString();
            } catch (e) {
              result = numMatch[1];
            }
          }
        }
      }
    } else if (selectedLang === 'javascript') {
      if (code.includes('console.log(')) {
        const match = code.match(/console\.log\(["\'](.+?)["\']\)/);
        if (match) result = match[1];
        else {
          const varMatch = code.match(/console\.log\((\w+)\)/);
          if (varMatch) {
            const varName = varMatch[1];
            const varLine = code.match(new RegExp(varName + '\\s*=\\s*["\'](.+?)["\']'));
            if (varLine) result = varLine[1];
          }
        }
      }
    } else if (selectedLang === 'html') {
      if (code.includes('<h1>')) result = '<h1>Hello World</h1>';
      else if (code.includes('color: red')) result = 'color: red';
    } else if (selectedLang === 'css') {
      if (code.includes('color: red')) result = 'color: red';
      else if (code.includes('background-color: yellow')) result = 'background-color: yellow';
    }

    setOutput(result);

    if (result && (lesson.expected === result || result.includes(lesson.expected) || lesson.expected.includes(result))) {
      const lessonKey = `${selectedLang}-${currentLesson}`;
      if (!completed.includes(lessonKey)) {
        const newCompleted = [...completed, lessonKey];
        setCompleted(newCompleted);
        setXp(xp + 10);
        saveUserData(); // Auto-save progress
      }
    }
  };

  const openQuizPage = () => {
    setCurrentPage('quiz');
    setQuizAnswers({});
    setQuizSubmitted(false);
  };

  const selectQuizAnswer = (questionIndex, optionIndex) => {
    setQuizAnswers({ ...quizAnswers, [questionIndex]: optionIndex });
  };

  const submitQuiz = () => {
    const currentLessonData = LESSONS[selectedLang][currentLesson];
    let score = 0;
    currentLessonData.quiz.forEach((q, idx) => {
      if (quizAnswers[idx] === q.correct) score++;
    });
    setQuizScore(score);
    setQuizSubmitted(true);
    if (score === currentLessonData.quiz.length) {
      setXp(xp + 20);
      const quizKey = `${selectedLang}-${currentLesson}-quiz`;
      if (!completed.includes(quizKey)) {
        const newCompleted = [...completed, quizKey];
        setCompleted(newCompleted);
        saveUserData(); // Auto-save progress
      }
    }
  };

  const closeQuiz = () => {
    setShowQuiz(false);
    setQuizAnswers({});
    setQuizSubmitted(false);
  };

  const prevLesson = () => {
    if (currentLesson > 0) setCurrentLesson(currentLesson - 1);
  };

  const nextLesson = () => {
    if (currentLesson < LESSONS[selectedLang].length - 1) setCurrentLesson(currentLesson + 1);
  };

  const refreshLeaderboard = () => {
    loadLeaderboard();
  };

  const sendDoubt = async () => {
    if (doubtMsg.trim() && username) {
      const newDoubt = {
        user: username,
        msg: doubtMsg,
        time: 'Just now',
        userId: userId
      };

      // Add to local doubts
      setDoubts([...doubts, newDoubt]);

      // Send to backend for global sharing
      try {
        await fetch('http://localhost:5001/api/doubts', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(newDoubt)
        });
        loadGlobalDoubts(); // Refresh global doubts
      } catch (error) {
        console.log('Saving doubt locally for now');
      }

      setDoubtMsg('');
    }
  };

  // Auto-save when XP changes
  useEffect(() => {
    if (userId && username) {
      saveUserData();
    }
  }, [xp, completed]);

  const progress = ((completed.filter(c => c.startsWith(selectedLang)).length / LESSONS[selectedLang].length) * 100).toFixed(0);
  const isLessonComplete = completed.includes(`${selectedLang}-${currentLesson}`) || completed.includes(`${selectedLang}-${currentLesson}-quiz`);

  return (
    <>
      {/* Setup Modal */}
      {showSetup && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4">
          <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white'} rounded-2xl p-8 max-w-md w-full`}>
            <h2 className="text-2xl font-bold mb-4">Welcome to CodeLearn! 🚀</h2>
            <p className="mb-6">Choose a nickname to track your progress and appear on the leaderboard:</p>
            <input
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              placeholder="Enter your nickname..."
              className={`w-full border rounded-lg px-4 py-3 mb-4 focus:outline-none focus:border-blue-500 ${
                theme === 'dark' ? 'bg-gray-700 border-gray-600 text-white placeholder-gray-400' : 'bg-gray-100 border-gray-300 text-gray-900 placeholder-gray-500'
              }`}
              maxLength={20}
            />
            <div className="flex gap-3">
              <button
                onClick={saveUsername}
                disabled={!username.trim()}
                className="flex-1 py-3 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed rounded-xl font-bold"
              >
                Start Learning!
              </button>
            </div>
            <p className="text-xs text-gray-400 mt-4">
              No registration required - just a nickname to track your progress!
            </p>
          </div>
        </div>
      )}

      <div className={`min-h-screen flex ${theme === 'dark' ? 'bg-gray-900 text-white' : 'bg-gray-50 text-gray-900'}`}>
        {/* Left Sidebar */}
        <div className={`w-64 ${theme === 'dark' ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'} border-r`}>
          <div className="p-6">
            <div className="flex items-center gap-3 mb-8">
              <div className="bg-gradient-to-r from-blue-500 to-purple-600 p-2 rounded-lg">
                <Code size={24} className="text-white" />
              </div>
              <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">
                CodeLearn
              </h1>
            </div>

            <nav className="space-y-2">
              {[
                { id: 'learn', icon: <BookOpen size={20} />, label: 'Learn' },
                { id: 'quiz', icon: <Trophy size={20} />, label: 'Quiz' },
                { id: 'journey', icon: <Flame size={20} />, label: 'Journey' },
                { id: 'leaderboard', icon: <Star size={20} />, label: 'Leaderboard' },
                { id: 'chat', icon: <MessageCircle size={20} />, label: 'Global Chat' },
              ].map((item) => (
                <button
                  key={item.id}
                  onClick={() => setCurrentPage(item.id)}
                  className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
                    currentPage === item.id
                      ? `${theme === 'dark' ? 'bg-gray-700' : 'bg-blue-50 text-blue-600'} font-medium`
                      : `${theme === 'dark' ? 'hover:bg-gray-700' : 'hover:bg-gray-100'}`
                  }`}
                >
                  {item.icon}
                  <span>{item.label}</span>
                </button>
              ))}
              <button
                onClick={() => setCurrentPage('profile')}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
                  currentPage === 'profile'
                    ? `${theme === 'dark' ? 'bg-gray-700' : 'bg-blue-50 text-blue-600'} font-medium`
                    : `${theme === 'dark' ? 'hover:bg-gray-700' : 'hover:bg-gray-100'}`
                }`}
              >
                <div className="w-8 h-8 bg-gradient-to-r from-purple-500 to-pink-500 rounded-full flex items-center justify-center text-white font-bold text-sm">
                  U
                </div>
                <span>Profile</span>
              </button>
            </nav>
          </div>

          <div className={`p-6 border-t ${theme === 'dark' ? 'border-gray-700' : 'border-gray-200'}`}>
            <div className="flex items-center gap-2 mb-3">
              <Flame size={20} className="text-orange-500" />
              <span className="font-bold">{streak} day streak</span>
            </div>
            <div className="flex items-center gap-2">
              <Trophy size={20} className="text-yellow-500" />
              <span className="font-bold">{xp} XP</span>
            </div>
          </div>
        </div>

        {/* Main Content Area */}
        <div className="flex-1">
          {/* Header */}
          <header className={`${theme === 'dark' ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'} border-b px-6 py-4`}>
            <div className="flex items-center justify-between">
              <h2 className="text-xl font-bold capitalize">{currentPage}</h2>
              <button
                onClick={toggleTheme}
                className={`flex items-center gap-2 px-4 py-2 rounded-full transition-colors ${
                  theme === 'dark' ? 'bg-gray-700 hover:bg-gray-600 text-yellow-400' : 'bg-gray-200 hover:bg-gray-300 text-orange-500'
                }`}
              >
                {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
                <span className="font-medium">{theme === 'dark' ? 'Light' : 'Dark'}</span>
              </button>
            </div>
          </header>

          {/* Learn Page */}
          {currentPage === 'learn' && (
            <>
              <div className={`${theme === 'dark' ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'} border-b px-6 py-3`}>
                <div className="max-w-7xl mx-auto flex gap-3">
                  {LANGUAGES.map((lang) => (
                    <button
                      key={lang.id}
                      onClick={() => { setSelectedLang(lang.id); setCurrentLesson(0); }}
                      className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${
                        selectedLang === lang.id
                          ? `${theme === 'dark' ? 'bg-gray-700 text-white' : 'bg-blue-100 text-blue-900'} ring-2 ring-blue-500`
                          : `${theme === 'dark' ? 'bg-gray-800 text-gray-400 hover:bg-gray-700' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`
                      }`}
                    >
                      <span>{lang.icon}</span>
                      <span className="font-medium">{lang.name}</span>
                      {completed.filter(c => c.startsWith(lang.id)).length === LESSONS[lang.id].length && (
                        <CheckCircle size={16} className="text-green-500" />
                      )}
                    </button>
                  ))}
                </div>
              </div>

              <main className="max-w-7xl mx-auto p-6 grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Left Column */}
                <div className="space-y-4">
                  <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-4`}>
                    <div className="flex items-center justify-between mb-2">
                      <span className={`text-sm ${theme === 'dark' ? 'text-gray-400' : 'text-gray-600'}`}>Course Progress</span>
                      <span className="text-sm font-bold text-blue-400">{progress}%</span>
                    </div>
                    <div className={`h-2 ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-200'} rounded-full overflow-hidden`}>
                      <div className="h-full bg-gradient-to-r from-blue-500 to-purple-500 transition-all" style={{ width: `${progress}%` }} />
                    </div>
                  </div>

                  <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-6`}>
                    <div className="flex items-center gap-2 mb-4">
                      <BookOpen size={20} className="text-blue-400" />
                      <span className={`text-sm ${theme === 'dark' ? 'text-gray-400' : 'text-gray-600'}`}>
                        Lesson {currentLesson + 1} of {LESSONS[selectedLang].length}
                      </span>
                      <span className={`px-2 py-1 rounded text-xs font-bold ${lesson.difficulty === 'beginner' ? 'bg-green-500/20 text-green-400' : 'bg-yellow-500/20 text-yellow-400'}`}>
                        {lesson.difficulty.toUpperCase()}
                      </span>
                    </div>
                    <h2 className="text-2xl font-bold mb-4">{lesson.title}</h2>
                    <p className={`${theme === 'dark' ? 'text-gray-300' : 'text-gray-700'} mb-6 leading-relaxed`}>{lesson.content}</p>

                    {/* Step-by-step guidance */}
                    {lesson.steps && (
                      <div className="mb-6">
                        <h4 className="font-bold mb-3 flex items-center gap-2">
                          <span>📝</span> Step-by-Step Instructions:
                        </h4>
                        <div className="space-y-2">
                          {lesson.steps.map((step, idx) => (
                            <div key={idx} className={`flex items-start gap-3 p-3 rounded-lg ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'}`}>
                              <div className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold ${theme === 'dark' ? 'bg-blue-600 text-white' : 'bg-blue-500 text-white'}`}>
                                {idx + 1}
                              </div>
                              <p className={`text-sm ${theme === 'dark' ? 'text-gray-300' : 'text-gray-700'}`}>{step}</p>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                    {/* Code example */}
                    {lesson.example && (
                      <div className="mb-6">
                        <h4 className="font-bold mb-3 flex items-center gap-2">
